```class Solution {
    public int possibleStringCount(String word, int k) {
        int MOD = 1000000007;
        int n = word.length();
        int[] count = new int[26];
        for (int i = 0; i < n; i++) {
            count[word.charAt(i) - 'a']++;
        }
        long res = 1;
        for (int i = 0; i < 26; i++) {
            res = res * (count[i] + 1) % MOD;
        }
        for (int i = 0; i < 26; i++) {
            res = res * (count[i]) % MOD;
        }
        return (int) (res % MOD);
    }
}
